// AI categorization: cluster 50 results into 4-8 categories using Claude Haiku
const input = $input.first().json;
const runId = input.run_id;
const projectId = input.project_id;
const niche = input.niche_description || '';

// Fetch all results for this run
const results = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/research_results?run_id=eq.${runId}&select=id,source,raw_text,engagement_score,source_url&order=engagement_score.desc`,
  headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` },
});

if (!results || results.length === 0) {
  return [{ json: { success: false, error: 'No results to categorize' } }];
}

// Build prompt
const prompt = `You are a content strategist analyzing ${results.length} discussion topics from 5 online sources.
All topics relate to the niche: ${niche}.

Tasks:
1. Group into organic categories by theme (typically 4-8, let data determine).
2. Per category: label (3-6 words), summary (2-3 sentences), top_video_title (best YouTube title from cluster)
3. Rank by total engagement_score.

Topics:
${JSON.stringify(results.map(r => ({ text: r.raw_text.substring(0, 200), source: r.source, engagement: r.engagement_score })))}

Respond ONLY in JSON: [{"label":"...","summary":"...","top_video_title":"...","result_ids":[...indices]}]`;

try {
  const aiResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 2048, messages: [{ role: 'user', content: prompt }] }),
  });

  const text = aiResp.content?.[0]?.text || '';
  let categories;
  try { categories = JSON.parse(text); } catch {
    const m = text.match(/\[[\s\S]*\]/);
    categories = m ? JSON.parse(m[0]) : [];
  }

  // Insert categories and update results
  for (let i = 0; i < categories.length; i++) {
    const cat = categories[i];
    const totalEngagement = (cat.result_ids || []).reduce((sum, idx) => sum + (results[idx]?.engagement_score || 0), 0);

    // Insert category
    const inserted = await this.helpers.httpRequest({
      method: 'POST',
      url: `${process.env.SUPABASE_URL}/rest/v1/research_categories`,
      headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({ run_id: runId, project_id: projectId, label: cat.label, summary: cat.summary, top_video_title: cat.top_video_title, total_engagement: totalEngagement, result_count: (cat.result_ids || []).length, rank: i + 1 }),
    });

    const catId = inserted?.[0]?.id;
    if (catId && cat.result_ids) {
      // Update results with category_id and ai_video_title
      for (const idx of cat.result_ids) {
        if (results[idx]) {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: `${process.env.SUPABASE_URL}/rest/v1/research_results?id=eq.${results[idx].id}`,
            headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
            body: JSON.stringify({ category_id: catId, ai_video_title: cat.top_video_title }),
          });
        }
      }
    }
  }

  // Update run status
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_runs?id=eq.${runId}`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'complete', total_categories: categories.length, completed_at: new Date().toISOString() }),
  });

  return [{ json: { success: true, categories: categories.length, results_categorized: results.length } }];
} catch (e) {
  // Update run as failed
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_runs?id=eq.${runId}`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'failed', error_log: [{ stage: 'categorize', error: e.message }] }),
  });
  return [{ json: { success: false, error: e.message } }];
}
